1	package aisuite
2	
3	import "encoding/json"
4	
5	type AISuite struct {
6		Identification `json:",inline"`
7		Description    string `json:"description"`
8	}
9	
10	type Identification struct {
11		SourceRegistry string `json:"sourceRegistry"`
12		Name           string `json:"name"`
13		ChartVersion   string `json:"chartVersion"`
14	}
15	
16	// 同名套件，使用最新版本的Description
17	type ProfileAISuite struct {
18		Name        string          `json:"name"`
19		Status      string          `json:"status"` // e.g. "deployed", "not_deployed"
20		Description string          `json:"description"`
21		Version     *AISuiteVersion `json:"version"`
22		Namespace   string          `json:"namespace,omitempty"` // NameSpace字段仅对已部署的套件有意义，表示当前部署的命名空间
23	}
24	
25	type AISuiteVersion struct {
26		AppVersion     string `json:"appVersion"`
27		ChartVersion   string `json:"chartVersion"`
28		Revision       int    `json:"revision,omitempty"` // Revision字段仅对已部署的套件有意义，表示当前部署的版本修订号
29		DisplayVersion string `json:"displayVersion"`
30	}
31	
32	type CustomValues struct {
33		Name  string `json:"name"`
34		Value any    `json:"value"`
35	}
36	
37	// --------- 前后端接口 ---------
38	
39	type ListAISuitesReq struct {
40		ClusterType string `form:"clusterType,default:normal" binding:"oneof=normal multiCloud"`
41		ClusterCode string `form:"clusterCode" binding:"required"`
42	}
43	
44	type ListAISuitesResp struct {
45		Total int               `json:"total"`
46		Data  []*ProfileAISuite `json:"data"`
47	}
48	
49	type GetAISuiteReq struct {
50		Name         string `uri:"name"`
51		ClusterCode  string `form:"clusterCode" binding:"required"`
52		ChartVersion string `form:"chartVersion"`
53		Namespace    string `form:"namespace"`
54	}
55	
56	type GetAISuiteResp struct {
57		ProfileAISuite    *ProfileAISuite   `json:",inline"`
58		InCluster         bool              `json:"inCluster"`
59		MaxRevision       int               `json:"maxRevision,omitempty"` // MaxRevision字段仅对已部署的套件有意义，表示当前套件的最大版本修订号
60		VersionList       []*AISuiteVersion `json:"versionList"`
61		CustomValueSchema json.RawMessage   `json:"customValueSchema"`
62	}
63	
64	type GetAISuiteReadmeReq struct {
65		Name         string `uri:"name"`
66		ChartVersion string `form:"chartVersion" binding:"required"`
67	}
68	
69	type GetAISuiteReadmeResp struct {
70		Readme string `json:"readme"`
71	}
72	
73	type OperateAISuiteReq struct {
74		Name         string          `uri:"name"`
75		Action       string          `json:"action" binding:"required,oneof=deploy upgrade uninstall"`
76		ClusterCode  string          `json:"clusterCode" binding:"required"`
77		Namespace    string          `json:"namespace" binding:"required_unless=Action deploy"`       // Namespace字段仅在部署操作中有意义，表示要部署到的命名空间
78		ChartVersion string          `json:"chartVersion" binding:"required_unless=Action uninstall"` // ChartVersion字段仅在部署和更新操作中有意义，表示要部署或更新到的版本
79		CustomValues []*CustomValues `json:"customValues" binding:"required_unless=Action uninstall"` // CustomValues字段仅在部署和更新操作中有意义，表示用户自定义的值
80	}
81	
82	type OperateAISuiteResp struct {
83		Message string `json:"message"`
84	}
85

1	package harbor
2	
3	import (
4		"context"
5		"fmt"
6		"strings"
7	
8		"github.com/mittwald/goharbor-client/v5/apiv2/model"
9		"github.com/mittwald/goharbor-client/v5/apiv2/pkg/config"
10	
11		"code.srdcloud.cn/TDP-PaaS/TDP-CODE/paas-controller/pkg/db"
12		"code.srdcloud.cn/TDP-PaaS/TDP-CODE/paas-controller/pkg/log"
13	)
14	
15	// ListRepositories 列出指定 Harbor 项目中的所有镜像仓库
16	func ListRepositories(ctx context.Context, registryConfig *db.Repository, projectName string, opts *config.Options) ([]*model.Repository, error) {
17		client, err := GetRegistryClient(registryConfig, opts)
18		if err != nil {
19			return nil, err
20		}
21	
22		repositories, err := client.GetClient().ListRepositories(ctx, projectName)
23		if err != nil {
24			return nil, fmt.Errorf("failed to list repositories from project %s in registry %s: %w", projectName, registryConfig.Name, err)
25		}
26	
27		return repositories, nil
28	}
29	
30	// GetRepository 获取指定 Harbor 项目中的单个镜像仓库详情
31	func GetRepository(ctx context.Context, registryConfig *db.Repository, projectName, repositoryName string, opts *config.Options) (*model.Repository, error) {
32		client, err := GetRegistryClient(registryConfig, opts)
33		if err != nil {
34			return nil, err
35		}
36	
37		repository, err := client.GetClient().GetRepository(ctx, projectName, repositoryName)
38		if err != nil {
39			return nil, fmt.Errorf("failed to get repository %s/%s from registry %s: %w", projectName, repositoryName, registryConfig.Name, err)
40		}
41	
42		return repository, nil
43	}
44	
45	// DeleteRepository 删除指定的镜像仓库
46	func DeleteRepository(ctx context.Context, registryConfig *db.Repository, projectName, repositoryName string) error {
47		client, err := GetRegistryClient(registryConfig, nil)
48		if err != nil {
49			return err
50		}
51	
52		err = client.GetClient().DeleteRepository(ctx, projectName, repositoryName)
53		if err != nil {
54			return fmt.Errorf("failed to delete repository %s/%s in registry %s: %w", projectName, repositoryName, registryConfig.Name, err)
55		}
56	
57		log.Infof("Deleted repository %s/%s in registry %s", projectName, repositoryName, registryConfig.Name)
58		return nil
59	}
60	
61	func GetSimpleRepoName(fullRepoName string) string {
62		// Harbor 的 repository 全称格式是 projectName/repoName，所以简单的 repoName 是全称去掉 projectName 和斜杠后的部分
63		// 例如：fullRepoName = "myproject/myrepo"，则简单 repoName 是 "myrepo"
64		parts := strings.SplitN(fullRepoName, "/", 2)
65		if len(parts) == 2 {
66			return parts[1]
67		}
68		return fullRepoName // 如果格式不符合预期，返回原始字符串
69	}
