31		suiteProjectPrefix  = "zzzz_internal_ai_suite"
32		suiteChartProject   = suiteProjectPrefix + "_helm_charts"
33		chartArtifactType   = "CHART"
34		jsonSchemaFileName  = "tap_aisuite_values.json"
35		readmeFileName      = "README.md"
36		aisuiteReleaseLabel = "DeployedBy=TAPAISuite"
37		maxSchemaSize       = 1024 * 1024 // 单位：字节
38		wait                = true
39		waitTimeout         = 10 * time.Minute
40		helmParamPrefix     = "tap_aisuite_"
41	)
