60	func (c *Controller) ListAISuites(ctx *gin.Context, clusterCode string) (*aisuite.ListAISuitesResp, error) {
61		suiteRegistry, err := getSuiteRegistry(c.db)
62		var aiSuitesInRegistry []*aisuite.ProfileAISuite
63		if err != nil {
64			log.Errorf("failed to get suite registry: %v", err)
65		} else {
66			aiSuitesInRegistry, err = listAISuitesInRegistry(ctx, suiteRegistry)
67			if err != nil {
68				log.Errorf("failed to list AI Suites in registry: %v", err)
69			}
70		}
71	
72		aiSuitesInCluster, err := c.listAISuitesInCluster(clusterCode)
73		// 如果查询集群内套件失败，应该直接返回报错，防止用户下一步操作部署一个已经在集群里部署了的套件（因为用户看不到集群里的套件列表，以为没有，所以又部署了一个）
74		if err != nil {
75			log.Errorf("failed to list AI Suites in cluster: %v", err)
76			return nil, fmt.Errorf("failed to list AI Suites in cluster: %w", err)
77		}
78	
79		// 入参底层数组可能会被修改，如果后面要增加逻辑，注意处理
80		aiSuites := disruptiveMergeAiSuites(aiSuitesInRegistry, aiSuitesInCluster)
81		sort.Slice(aiSuites, func(i, j int) bool {
82			return aiSuites[i].Name < aiSuites[j].Name
83		})
84		return &aisuite.ListAISuitesResp{
85			Total: len(aiSuites),
86			Data:  aiSuites,
87		}, nil
88	}
89	
90	func (c *Controller) GetAISuite(ctx *gin.Context, clusterCode, name, chartVersion, namespace string) (*aisuite.GetAISuiteResp, error) {
91		// 从集群和registry中查询套件
92		suiteInCluster, err := c.getAISuiteInCluster(clusterCode, name, chartVersion, namespace)
93		if err != nil {
94			log.Errorf("encountered error while getting AI Suite in cluster: %v", err)
95			if namespace != "" {
96				return nil, fmt.Errorf("encountered error while getting AI Suite in cluster: %w", err)
97			}
98		}
99	
100		suiteInRegistry := new(aisuite.GetAISuiteResp)
101		suiteRegistry, err := getSuiteRegistry(c.db)
102		if err != nil {
103			log.Errorf("failed to get suite registry: %v", err)
104		} else {
105			suiteInRegistry, err = getAISuiteInRegistry(ctx, suiteRegistry, name, chartVersion)
106			if err != nil {
107				log.Errorf("encountered error while getting AI Suite in registry: %v", err)
108				suiteInRegistry = nil
109			}
110		}
111	
112		switch {
113		case suiteInCluster == nil && suiteInRegistry == nil:
114			return nil, fmt.Errorf("AI Suite %s not found in both cluster and registry", name)
115		case suiteInCluster != nil && suiteInRegistry == nil:
116			return suiteInCluster, nil
117		case suiteInCluster == nil && suiteInRegistry != nil:
118			return suiteInRegistry, nil
119		case suiteInCluster != nil && suiteInRegistry != nil:
120			if suiteInCluster.ProfileAISuite != nil && suiteInCluster.ProfileAISuite.Version != nil {
121				inBoth := false
122				for _, version := range suiteInRegistry.VersionList {
123					if version.DisplayVersion == suiteInCluster.ProfileAISuite.Version.DisplayVersion {
124						suiteInCluster.VersionList = suiteInRegistry.VersionList
125						inBoth = true
126						break
127					}
128				}
129				if !inBoth {
130					suiteInCluster.VersionList = append(suiteInCluster.VersionList, suiteInCluster.ProfileAISuite.Version)
131				}
132				// TODO: 用已部署套件的values的值覆盖schame中的默认值，提供给前端展示
133				// setValues, err := c.apiserverGetter.GetHelmReleaseValues(clusterCode, namespace, name, suiteInCluster.ProfileAISuite.Version.Revision, true)
134				// if err != nil {
135				// 	log.Errorf("failed to get helm release values: %v", err)
136				// }
137				// setValues中是嵌套map[string]interface{}的结构，需要转换成json字符串再赋值给CustomValueSchema中的
138			}
139			suiteInCluster.CustomValueSchema = suiteInRegistry.CustomValueSchema
140			return suiteInCluster, nil
141		}
142		return nil, nil
143	}
