145	func (c *Controller) GetAISuiteReadme(ctx context.Context, name, chartVersion string) (*aisuite.GetAISuiteReadmeResp, error) {
146		// 使用oras拉取chart，解压后读取其中的README.md, 作为套件的README内容
147		suiteRegistry, err := getSuiteRegistry(c.db)
148		if err != nil {
149			log.Errorf("failed to get suite registry: %v", err)
150			return nil, fmt.Errorf("failed to get suite registry: %w", err)
151		}
152		orasClient, err := oras.NewClient(suiteRegistry, oras.Insecure())
153		if err != nil {
154			log.Errorf("failed to create oras client: %v", err)
155			return nil, fmt.Errorf("failed to create oras client: %w", err)
156		}
157		artifactRef := fmt.Sprintf("%s/%s:%s", suiteChartProject, name, chartVersion)
158		readmeBytes, err := orasClient.PullFile(ctx, artifactRef, readmeFileName, maxSchemaSize)
159		if err != nil {
160			log.Errorf("failed to pull README.md for AI Suite %s:%s: %v", name, chartVersion, err)
161			return nil, fmt.Errorf("failed to pull README.md for AI Suite %s:%s: %w", name, chartVersion, err)
162		}
163		return &aisuite.GetAISuiteReadmeResp{Readme: string(readmeBytes)}, nil
164	}
