590	// expandDotKey inserts a value into a nested map by expanding dot-separated keys.
591	// E.g. expandDotKey(m, "global.image.tag", "v1.0.0") sets m["global"]["image"]["tag"] = "v1.0.0".
592	// This matches the behavior of `helm install --set global.image.tag=v1.0.0`.
593	func expandDotKey(m map[string]interface{}, key string, value interface{}) {
594		dotIdx := strings.Index(key, ".")
595		if dotIdx == -1 {
596			m[key] = value
597			return
598		}
599		prefix := key[:dotIdx]
600		rest := key[dotIdx+1:]
601		sub, ok := m[prefix].(map[string]interface{})
602		if !ok {
603			sub = make(map[string]interface{})
604			m[prefix] = sub
605		}
606		expandDotKey(sub, rest, value)
607	}
