141	func (c *Controller) syncTenants() (deletedTenantIds []uint64, err error) {
142		corps, err := c.manager.ListAllCorp()
143		if err != nil {
144			log.Errorf("list corps: %v", err)
145			return nil, err
146		}
147		tx := c.db.Begin()
148		defer func() {
149			if err != nil {
150				tx.Rollback()
151				return
152			}
153			err = tx.Commit().Error
154		}()
155		model := &db.Tenant{}
156		oldTenants, _, err := model.Gets(tx, 0, 0)
157		if err != nil {
158			log.Errorf("list tenants: %v", err)
159			return nil, err
160		}
161		willUpdateTenants := make([]db.Tenant, 0)
162		willCreateTenants := make([]db.Tenant, 0)
163		willDeleteTenantIds := make([]uint64, 0)
164		oldTenantsMap := make(map[string]db.Tenant)
165		for _, tenant := range oldTenants {
166			oldTenantsMap[tenant.Code] = tenant
167		}
168	
169		for _, corp := range corps {
170			oldTenant, found := oldTenantsMap[corp.CorpCode]
171			if found {
172				if oldTenant.Name != corp.CorpName || oldTenant.Description != corp.Desc {
173					oldTenant.Name = corp.CorpName
174					oldTenant.Description = corp.Desc
175					willUpdateTenants = append(willUpdateTenants, oldTenant)
176				}
177				delete(oldTenantsMap, corp.CorpCode)
178			} else {
179				newTenant := db.Tenant{
180					Name:        corp.CorpName,
181					Code:        corp.CorpCode,
182					Description: corp.Desc,
183					Model: db.Model{
184						CreatedAt: time.UnixMilli(corp.CreateTime).Local(),
185					},
186				}
187				willCreateTenants = append(willCreateTenants, newTenant)
188			}
189		}
190		for _, tenant := range oldTenantsMap {
