324					},
325				}
326				willCreateProjects = append(willCreateProjects, newProject)
327			}
328		}
329		for _, project := range oldProjectsMap {
330			willDeleteProjectIds = append(willDeleteProjectIds, project.Id)
331		}
332		if len(willUpdateProjects) > 0 {
333			err = model.Updates(tx, willUpdateProjects)
334			if err != nil {
335				log.Errorf("update projects: %v", err)
336				return nil, err
337			}
338		}
339		if len(willCreateProjects) > 0 {
340			err = model.Creates(tx, willCreateProjects)
341			if err != nil {
342				log.Errorf("create projects: %v", err)
343				return nil, err
344			}
345		}
