18	type PvcCache struct {
19		informerFactory informers.SharedInformerFactory
20		pvInformer      cache.SharedIndexInformer
21		pvLister        corev1listers.PersistentVolumeLister
22		pvcInformer     cache.SharedIndexInformer
23		pvcLister       corev1listers.PersistentVolumeClaimLister
24		subPathPvcMap   sync.Map
25	}
26	
27	func NewPvcCache(i informers.SharedInformerFactory) *PvcCache {
28		informerFactory := i
29		return &PvcCache{
30			informerFactory: informerFactory,
31			pvInformer:      informerFactory.Core().V1().PersistentVolumes().Informer(),
32			pvLister:        informerFactory.Core().V1().PersistentVolumes().Lister(),
33			pvcInformer:     informerFactory.Core().V1().PersistentVolumeClaims().Informer(),
34			pvcLister:       informerFactory.Core().V1().PersistentVolumeClaims().Lister(),
35		}
36	}
37	
38	func (p *PvcCache) AddEventHandle() {
39		_, err := p.pvcInformer.AddEventHandler(cache.ResourceEventHandlerFuncs{
40			AddFunc:    p.onPVCAdd,
41			DeleteFunc: p.onPVCDelete,
42		})
43		if err != nil {
44			log.Errorf("pvc informer add eventHandler err: %v", err)
45		}
46	}
47	
48	// onPVCAdd 当 PVC 新增时，根据绑定的 PV 查找 subPath 并保存映射
49	func (p *PvcCache) onPVCAdd(obj interface{}) {
50		pvc, ok := obj.(*corev1.PersistentVolumeClaim)
51		if !ok {
52			return
53		}
54		// 未绑定 PV 的 PVC 跳过
55		if pvc.Spec.VolumeName == "" {
56			return
57		}
58	
59		pv, err := p.pvLister.Get(pvc.Spec.VolumeName)
60		if err != nil {
61			if errors.IsNotFound(err) {
62				return // PV 还没出现
63			}
64			klog.Errorf("get PV %s for PVC %s/%s failed: %v", pvc.Spec.VolumeName, pvc.Namespace, pvc.Name, err)
65			return
66		}
67	
68		var subPath string
69		if pv.Spec.CSI != nil {
70			if val, ok := pv.Spec.CSI.VolumeAttributes["subPath"]; ok {
71				subPath = val
72			}
73		}
74		key := fmt.Sprintf("%s,%s", pvc.Namespace, subPath)
75	
76		if subPath != "" {
77			p.subPathPvcMap.Store(key, pvc)
78		}
79	
80	}
81	
82	func (p *PvcCache) onPVCDelete(obj interface{}) {
83		pvc, ok := obj.(*corev1.PersistentVolumeClaim)
84		if !ok {
85			return
86		}
87		if pvc.Spec.VolumeName == "" {
88			return
89		}
90		pv, err := p.pvLister.Get(pvc.Spec.VolumeName)
91		if err != nil {
92			// PV 可能还未缓存到，可以后续同步
93			return
94		}
95	
96		var subPath string
97		if pv.Spec.CSI != nil {
98			if val, ok := pv.Spec.CSI.VolumeAttributes["subPath"]; ok {
99				subPath = val
100			}
101		}
102		key := fmt.Sprintf("%s,%s", pvc.Namespace, subPath)
103		p.subPathPvcMap.Delete(key)
104	
105	}
106	
107	// GetPVCFromSubPath 查询 pvc
108	func (p *PvcCache) GetPVCFromSubPath(namespace, subPath string) (*corev1.PersistentVolumeClaim, bool) {
109		key := fmt.Sprintf("%s,%s", namespace, subPath)
110		v, ok := p.subPathPvcMap.Load(key)
111		if !ok {
112			return nil, false
113		}
114		return v.(*corev1.PersistentVolumeClaim), true
115	}
116	
117	func (p *PvcCache) GetPv(name string) (*corev1.PersistentVolume, error) {
118		return p.pvLister.Get(name)
119	}
