func (r *RegisterEventManagerImpl) Watch(registerHandler func(register.ApiserverInfo) error, deRegisterHandler func(clusterCode string) error) {
	for {
		event := <-r.events
		switch event.EventType {
		case Register:
			err := registerHandler(event.RegisterInfo)
			if err != nil {
				log.Error("handler register err: %v", err)
				r.AddRegisterEventDelay(&event, time.Second*5)
			}
		case Deregister:
			err := deRegisterHandler(event.DeregisterClusterCode)
			if err != nil {
				log.Error("handler deregister err: %v", err)
				r.AddRegisterEventDelay(&event, time.Second*5)
			}
		}
	}
}
